import socket

def tcp_scan(ip, ports):
    results = {}
    for port in ports:
        sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        sock.settimeout(2)
        try:
            result = sock.connect_ex((ip, port))
            results[port] = 'open' if result == 0 else 'closed'
        except (socket.timeout, OSError):
            results[port] = 'closed'
        finally:
            sock.close()
    return results

import struct

def is_pe_file(filepath):
    try:
        with open(filepath, 'rb') as f:
            header = f.read(64)
            if len(header) < 64:
                return False
            if header[:2] != b'MZ':
                return False
            e_lfanew = struct.unpack('<I', header[0x3C:0x40])[0]
            f.seek(e_lfanew)
            pe_sig = f.read(4)
            return pe_sig == b'PE\x00\x00'
    except (IOError, struct.error):
        return False

import re
from datetime import datetime
from collections import defaultdict

def detect_brute_force(log_lines, threshold=5, window_seconds=60):
    pattern = r'(\d+\.\d+\.\d+\.\d+).*\[(\d{2}/\w{3}/\d{4}:\d{2}:\d{2}:\d{2}).*"\s(\d{3})'
    failures = defaultdict(list)
    for line in log_lines:
        match = re.search(pattern, line)
        if match and match.group(3) == '401':
            ip = match.group(1)
            ts = datetime.strptime(match.group(2), '%d/%b/%Y:%H:%M:%S')
            failures[ip].append(ts)
    attackers = []
    for ip, timestamps in failures.items():
        timestamps.sort()
        for i in range(len(timestamps) - threshold + 1):
            if (timestamps[i + threshold - 1] - timestamps[i]).seconds <= window_seconds:
                attackers.append(ip)
                break
    return attackers

import requests

def audit_security_headers(url):
    findings = []
    response = requests.get(url, timeout=10)
    headers = response.headers
    checks = {
        'Content-Security-Policy': 'HIGH',
        'X-Frame-Options': 'MEDIUM',
        'Strict-Transport-Security': 'HIGH',
        'X-Content-Type-Options': 'LOW'
    }
    for header, severity in checks.items():
        if header not in headers:
            findings.append({
                'header': header,
                'status': 'MISSING',
                'severity': severity
            })
        else:
            findings.append({
                'header': header,
                'status': 'PRESENT',
                'value': headers[header],
                'severity': 'INFO'
            })
    return findings

import boto3
from botocore.exceptions import ClientError

def find_public_buckets():
    s3 = boto3.client('s3')
    public_buckets = []
    buckets = s3.list_buckets()['Buckets']
    for bucket in buckets:
        name = bucket['Name']
        try:
            acl = s3.get_bucket_acl(Bucket=name)
            for grant in acl['Grants']:
                grantee = grant.get('Grantee', {})
                uri = grantee.get('URI', '')
                if 'AllUsers' in uri or 'AuthenticatedUsers' in uri:
                    public_buckets.append({'bucket': name, 'reason': 'public_acl'})
                    break
        except ClientError as e:
            if e.response['Error']['Code'] == 'AccessDenied':
                public_buckets.append({'bucket': name, 'reason': 'access_denied_to_audit'})
    return public_buckets
